parameters.functionCode:
// Extract URLs from <loc>...</loc> in the sitemap XML.
// Sericia's sitemap.ts emits ~102 URLs (pSEO + tools + journal + products + brand pages).
// We hit each sequentially with a 200ms gap to stay friendly to the origin.
const xml = $input.first().json.data || $input.first().json.body || '';
const urls = Array.from(xml.matchAll(/<loc>([^<]+)<\/loc>/g)).map(m => m[1]);
return urls.map(url => ({ json: { url } }));

